        uniffiFree: { (uniffiHandle: UInt64) -> () in
            do {
                try FfiConverterTypeConversationObserver.handleMap.remove(handle: uniffiHandle)
            } catch {
                print("Uniffi callback interface ConversationObserver: handle missing in uniffiFree")
            }
        },
        uniffiClone: { (uniffiHandle: UInt64) -> UInt64 in
            do {
                return try FfiConverterTypeConversationObserver.handleMap.clone(handle: uniffiHandle)
            } catch {
                fatalError("Uniffi callback interface ConversationObserver: handle missing in uniffiClone")
            }
