    nonisolated(unsafe) static let vtablePtr: UnsafePointer<UniffiVTableCallbackInterfaceConversationObserver> = {
        let ptr = UnsafeMutablePointer<UniffiVTableCallbackInterfaceConversationObserver>.allocate(capacity: 1)
