#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public struct FfiConverterTypeTamtriCore: FfiConverter {
    typealias FfiType = UInt64
    typealias SwiftType = TamtriCore

    public static func lift(_ handle: UInt64) throws -> TamtriCore {
        return TamtriCore(unsafeFromHandle: handle)
    }

    public static func lower(_ value: TamtriCore) -> UInt64 {
        return value.uniffiCloneHandle()
    }

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> TamtriCore {
        let handle: UInt64 = try readInt(&buf)
